pure fn bmi(height_cm: Number, weight_kg: Number) -> Number {
    h_m = height_cm / 100
    return round(weight_kg / pow(h_m, 2), 2)
}
entry main(x: Text) { return bmi(175, 70) }

pure fn distance(x: Number, y: Number) -> Number {
    return sqrt(pow(x, 2) + pow(y, 2))
}
entry main(x: Text) { return distance(3, 4) }

pure fn compound(p: Number, r: Number, t: Number) -> Number {
    return round(p * pow(1 + r, t), 2)
}
entry main(x: Text) { return compound(1000, 0.05, 3) }

pure fn f(x: Number) -> Number { return floor(x) }
pure fn c(x: Number) -> Number { return ceil(x) }
entry main(x: Text) {
    return join([to_text(f(2.9)), to_text(c(2.1))], "-")
}

pure fn sum_list(xs: List[Number]) -> Number {
    total = 0
    for x in xs { total = total + x }
    return total
}
pure fn stddev(xs: List[Number]) -> Number {
    n = length(xs)
    mean = sum_list(xs) / n
    sq_diff = 0
    for x in xs { sq_diff = sq_diff + pow(x - mean, 2) }
    return round(sqrt(sq_diff / n), 3)
}
entry main(x: Text) { return stddev([2, 4, 4, 4, 5, 5, 7, 9]) }

pure fn hypotenuse(a: Number, b: Number) -> Number {
    return sqrt(a * a + b * b)
}
entry main(x: Text) { return hypotenuse(5, 12) }

pure fn area(r: Number) -> Number {
    return round(3.14159265 * pow(r, 2), 4)
}
entry main(x: Text) { return area(5) }

pure fn sum(xs: List[Number]) -> Number {
    total = 0
    for x in xs { total = total + x }
    return total
}
entry main(x: Text) { return sum([1, 2, 3, 4, 5]) }

pure fn largest(xs: List[Number]) -> Number {
    best = get(xs, 0)
    for x in xs {
        if x > best { best = x }
    }
    return best
}
entry main(x: Text) { return largest([34, 12, 89, 3, 56, 72]) }

pure fn average(scores: List[Number]) -> Number {
    total = 0
    for s in scores { total = total + s }
    return total / length(scores)
}
entry main(x: Text) { return average([85, 92, 78, 95, 88]) }

pure fn only_even(xs: List[Number]) -> List[Number] {
    out = []
    for x in xs {
        if x % 2 == 0 { out = append(out, x) }
    }
    return out
}
entry main(x: Text) {
    return join(only_even([1, 2, 3, 4, 5, 6, 7, 8]), ",")
}

pure fn safe_div(a: Number, b: Number) -> Result[Number] {
    if b == 0 { return error("divide by zero") }
    return ok(a / b)
}
entry main(x: Text) {
    r = safe_div(42, 6)
    if is_ok(r) { return unwrap(r) }
    return 0
}

intent health_comment(bmi: Number) -> Text {
    goal: a short health comment based on the BMI value
}
pure fn compute_bmi(h_cm: Number, w_kg: Number) -> Number {
    return round(w_kg / pow(h_cm / 100, 2), 2)
}
entry main(x: Text) {
    b = compute_bmi(175, 70)
    return join([to_text(b), " — ", health_comment(b)], "")
}

intent classify_sentiment(text: Text) -> Text {
    goal: sentiment as positive or negative or neutral
}
pure fn word_count(text: Text) -> Number {
    return length(split(text, " "))
}
entry main(text: Text) {
    n = word_count(text)
    s = classify_sentiment(text)
    return join([to_text(n), " words, ", s], "")
}

intent describe_performance(avg: Number) -> Text {
    goal: brief natural-language performance summary
}
pure fn avg(xs: List[Number]) -> Number {
    total = 0
    for x in xs { total = total + x }
    return round(total / length(xs), 2)
}
entry main(x: Text) {
    a = avg([72, 85, 90, 68, 77])
    return join([to_text(a), ": ", describe_performance(a)], "")
}

pure fn pass_or_fail(score: Number) -> Text {
    if score >= 80 { return "pass" }
    return "fail"
}
pure fn parse_entry(e: Text) -> Text {
    parts = split(e, ":")
    name = get(parts, 0)
    score = to_number(get(parts, 1))
    return join([name, ": ", pass_or_fail(score)], "")
}
entry main(text: Text) {
    entries = split(text, ",")
    out = []
    for e in entries { out = append(out, parse_entry(e)) }
    return join(out, "; ")
}

intent budget_tip(total: Number) -> Text {
    goal: one-sentence budgeting advice given the total
}
pure fn sum_list(xs: List[Number]) -> Number {
    total = 0
    for x in xs { total = total + x }
    return total
}
entry main(x: Text) {
    total = sum_list([12.5, 28.99, 7.4, 45.0, 16.8])
    return join([to_text(total), " — ", budget_tip(total)], "")
}

intent describe_spread(top: Number, bot: Number) -> Text {
    goal: one-line description of the range between top and bot
}
pure fn desc_sort(xs: List[Number]) -> List[Number] {
    return reverse(sort(xs))
}
entry main(x: Text) {
    s = desc_sort([42, 17, 8, 93, 55])
    top = get(s, 0)
    bot = get(s, length(s) - 1)
    return join([to_text(s), " — ", describe_spread(top, bot)], "")
}

intent classify_length(n: Number) -> Text {
    goal: concise or verbose based on character count
}
pure fn count_chars(s: Text) -> Number { return length(s) }
entry main(text: Text) {
    n = count_chars(text)
    return join([to_text(n), " chars — ", classify_length(n)], "")
}

intent summarize_items(items: List[Text]) -> Text {
    goal: one-sentence summary of the unique items
}
pure fn dedupe(items: List[Text]) -> List[Text] {
    seen = []
    for it in items {
        if it not in seen { seen = append(seen, it) }
    }
    return seen
}
entry main(x: Text) {
    unique = dedupe(["apple", "banana", "apple", "cherry", "banana"])
    return join([join(unique, ","), " — ", summarize_items(unique)], "")
}

intent explain_interest(principal: Number, final: Number) -> Text {
    goal: layperson explanation of the interest gain
}
pure fn final_amount(p: Number, r: Number, t: Number) -> Number {
    return round(p * pow(1 + r, t), 2)
}
entry main(x: Text) {
    final = final_amount(1000, 0.05, 3)
    return join([to_text(final), " — ", explain_interest(1000, final)], "")
}

intent timeline_ok(days: Number) -> Text {
    goal: one word tight reasonable or loose
}
pure fn diff(days_ago: Number) -> Number { return days_ago }
entry main(x: Text) {
    d = diff(10)
    return join([to_text(d), " days — ", timeline_ok(d)], "")
}

intent describe_pattern(text: Text) -> Text {
    goal: brief description of the text shape
}
pure fn char_count(s: Text) -> Number { return length(s) }
entry main(text: Text) {
    n = char_count(text)
    return join([to_text(n), " chars: ", describe_pattern(text)], "")
}

intent creative_sentence(words: List[Text]) -> Text {
    goal: one playful sentence using the supplied words
}
pure fn reverse_text(s: Text) -> Text {
    chars = split(s, "")
    out = ""
    for i in range(0, length(chars)) {
        out = join([out, get(chars, length(chars) - 1 - i)], "")
    }
    return out
}
pure fn reverse_each(text: Text) -> List[Text] {
    words = split(text, " ")
    out = []
    for w in words { out = append(out, reverse_text(w)) }
    return out
}
entry main(text: Text) {
    rev = reverse_each(text)
    return join([join(rev, " "), " — ", creative_sentence(rev)], "")
}

intent metaphor(overlap: List[Number]) -> Text {
    goal: a short metaphor describing the shared elements
}
pure fn common(a: List[Number], b: List[Number]) -> List[Number] {
    out = []
    for x in a {
        if x in b { out = append(out, x) }
    }
    return out
}
entry main(x: Text) {
    c = common([1,2,3,4,5], [3,4,5,6,7])
    return join([to_text(c), " — ", metaphor(c)], "")
}

intent fact_or_opinion(text: Text) -> Text {
    goal: the single word fact or opinion
}
entry main(text: Text) { return fact_or_opinion(text) }

intent detect_language(text: Text) -> Text {
    goal: the language name in English
}
entry main(text: Text) { return detect_language(text) }

intent simplify(text: Text) -> Text {
goal: plain English version suitable to a young child
}
entry main(text: Text) { return simplify(text) }

pure fn factorial(n: Number) -> Number {
    if n <= 1 { return 1 }
    return n * factorial(n - 1)
}
entry main(x: Text) { return factorial(7) }

pure fn sort_words(s: Text) -> Text {
    return join(sort(split(s, " ")), " ")
}
entry main(x: Text) { return sort_words("banana cherry apple date") }

pure fn sum_evens(n: Number) -> Number {
    total = 0
    for i in range(1, n + 1) {
        if i % 2 == 0 { total = total + i }
    }
    return total
}
entry main(x: Text) { return sum_evens(100) }

pure fn long_words(text: Text, min_len: Number) -> Number {
    count = 0
    for w in split(text, " ") {
        if length(w) > min_len { count = count + 1 }
    }
    return count
}
entry main(x: Text) {
    return long_words("the quick brown fox jumps over the lazy dog", 3)
}

pure fn f_to_c(f: Number) -> Number {
    return round((f - 32) * 5 / 9, 1)
}
entry main(x: Text) { return f_to_c(98.6) }

pure fn fizzbuzz(n: Number) -> Text {
    out = []
    for i in range(1, n + 1) {
        if i % 15 == 0 { out = append(out, "FizzBuzz") }
        else if i % 3 == 0 { out = append(out, "Fizz") }
        else if i % 5 == 0 { out = append(out, "Buzz") }
        else { out = append(out, to_text(i)) }
    }
    return join(out, ",")
}
entry main(x: Text) { return fizzbuzz(15) }

pure fn reverse_text(s: Text) -> Text {
    chars = split(s, "")
    out = ""
    for i in range(0, length(chars)) {
        out = join([out, get(chars, length(chars) - 1 - i)], "")
    }
    return out
}
pure fn is_palindrome(s: Text) -> Boolean {
    return lower(s) == reverse_text(lower(s))
}
entry main(x: Text) { return is_palindrome("racecar") }

pure fn dedupe(xs: List[Number]) -> List[Number] {
    seen = []
    for x in xs {
        if x not in seen { seen = append(seen, x) }
    }
    return seen
}
entry main(x: Text) {
    return join(dedupe([1, 3, 2, 3, 1, 4, 2, 5]), ",")
}

pure fn fib_list(n: Number) -> List[Number] {
    out = [0, 1]
    for i in range(2, n) {
        a = get(out, i - 1)
        b = get(out, i - 2)
        out = append(out, a + b)
    }
    return out
}
entry main(x: Text) { return join(fib_list(10), ",") }

pure fn div_by(xs: List[Number], d: Number) -> List[Number] {
    out = []
    for x in xs {
        if x % d == 0 { out = append(out, x) }
    }
    return out
}
entry main(x: Text) {
    return join(div_by([15, 23, 8, 42, 16, 4, 31], 4), ",")
}

pure fn count_vowels(text: Text) -> Number {
    vowels = ["a", "e", "i", "o", "u"]
    count = 0
    for c in split(lower(text), "") {
        if c in vowels { count = count + 1 }
    }
    return count
}
entry main(x: Text) { return count_vowels("Programming is fun") }

pure fn longest(text: Text) -> Text {
    best = ""
    for w in split(text, " ") {
        if length(w) > length(best) { best = w }
    }
    return best
}
entry main(x: Text) {
    return longest("extraordinary programming capabilities")
}

pure fn remove_stops(text: Text, stops: List[Text]) -> Text {
    out = []
    for w in split(text, " ") {
        if w not in stops { out = append(out, w) }
    }
    return join(out, " ")
}
entry main(x: Text) {
    return remove_stops("the cat is on the mat", ["the", "a", "is", "on", "at"])
}
